//

var loadExternalScript = (scriptUrl, callback) => {
  var script = document.createElement("script");
  script.src = scriptUrl;

  script.onload = () => {
    // console.log(scriptUrl + " loaded, ready for action");

    if (callback) {
      callback(scriptUrl, true); // succeed
    }
  };

  script.onerror = e => {
    // console.log(scriptUrl + " failed to load !");

    if (callback) {
      callback(scriptUrl, false); // failed
    }
  };

  document.head.appendChild(script);
};

//

document.documentElement.className = "js";
var supportsCssVars = function() {
  var e,
    t = document.createElement("style");
  return (
    (t.innerHTML = "root: { --tmp-var: bold; }"),
    document.head.appendChild(t),
    (e = !!(
      window.CSS &&
      window.CSS.supports &&
      window.CSS.supports("font-weight", "var(--tmp-var)")
    )),
    t.parentNode.removeChild(t),
    e
  );
};
supportsCssVars() ||
  alert(
    "Please view this demo in a modern browser that supports CSS Variables."
  );

//

module.exports = loadExternalScript;
